// Parse Slack interactive payload
const body = $input.first().json.body;
const payload = JSON.parse(body.payload);
const action = payload.actions[0];
const value = JSON.parse(action.value);

return [{
  json: {
    action: value.action,
    alert_id: value.alert_id,
    src_ip: value.src_ip,
    block_duration_hours: value.block_duration_hours || 2,
    risk_level: value.risk_level || 'HIGH',
    threat_type: value.threat_type || 'Unknown',
    mitre: value.mitre || 'Unknown'
  }
}];

const data = $('Parse Slack Payload').first().json;
return [{
  json: {
    src_ip: data.src_ip,
    block_duration_hours: data.block_duration_hours,
    reason: 'Admin approved block via Slack',
    risk_level: data.risk_level,
    threat_type: data.threat_type,
    mitre: data.mitre,
    anomaly_score: 0,
    triggered_by: 'admin_approval'
  }
}];
